// Triage rules — classify each email by subject/sender
const RULES = [
  { label: 'Opportunity RE', subjectMatch: /opportunity|deal|acquisition|off.?market|pocket.?listing/i },
  { label: 'Opportunity RE', fromMatch: /@crexi\.com|@loopnet\.com|@costar\.com/i },
  { label: 'Construction', subjectMatch: /draw.?request|change.?order|punch.?list|certificate.?of.?occupancy|permit/i },
  { label: 'Legal', subjectMatch: /LOI|letter.?of.?intent|contract|lease|amendment|estoppel|closing/i },
  { label: 'Finance', subjectMatch: /loan|mortgage|refinance|appraisal|underwriting|term.?sheet/i },
  { label: 'Finance', fromMatch: /@citynational\.com|@jpmorgan\.com/i },
  { label: 'Asset Mgmt', subjectMatch: /rent.?roll|NOI|occupancy|tenant|lease.?renewal|cap.?rate/i },
  { label: 'Team', fromMatch: /@privegroup\.com/i },
  { label: 'Scheduling', subjectMatch: /meeting|call|appointment|schedule|calendar/i },
];

const results = [];
for (const item of $input.all()) {
  const subject = item.json.subject || '';
  const from = item.json.from || '';
  const labels = [];
  let amandaRoute = null;

  for (const rule of RULES) {
    let matched = false;
    if (rule.subjectMatch && rule.subjectMatch.test(subject)) matched = true;
    if (rule.fromMatch && rule.fromMatch.test(from)) matched = true;
    if (matched && !labels.includes(rule.label)) labels.push(rule.label);
  }

  // Determine Amanda route
  const AMANDA_ROUTES = {
    'Opportunity RE': { action: 'OPPORTUNITY_RE_FASTSCAN', instruction: 'Run Fast Scan deal analysis.' },
    'Legal': { action: 'LEGAL_REVIEW', instruction: 'Review for key terms and red flags.' },
    'Construction': { action: 'CONSTRUCTION_REVIEW', instruction: 'Review construction communication.' },
    'Finance': { action: 'FINANCE_REVIEW', instruction: 'Review financial communication.' },
  };

  for (const label of labels) {
    if (AMANDA_ROUTES[label]) {
      amandaRoute = AMANDA_ROUTES[label];
      break; // First match wins
    }
  }

  results.push({
    json: {
      ...item.json,
      triageLabels: labels,
      amandaRoute,
      shouldForwardToAmanda: !!amandaRoute,
    }
  });
}

return results;

